#include &lt;bits/stdc++.h&gt;
using namespace std;

void towerOfHanoi(int n, char from_rod, char to_rod,
                char aux_rod)
{
    if (n == 0) {
        return;
    }
    towerOfHanoi(n - 1, from_rod, aux_rod, to_rod);
    cout &lt;&lt; &quot;Move disk &quot; &lt;&lt; n &lt;&lt; &quot; from rod &quot; &lt;&lt; from_rod
        &lt;&lt; &quot; to rod &quot; &lt;&lt; to_rod &lt;&lt; endl;
